INSERT INTO messages (message_id, channel_id, user_id, message_text, message_time) VALUES
  ('60000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'Welcome everyone to the CS Department workspace! Please introduce yourselves.', '2024-01-13 09:30:00'),
  ('60000000-0000-0000-0000-000000000002', '40000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002', 'Hi all! I am Bob, the TA for CS301 this semester. Happy to be here.', '2024-01-13 10:00:00'),
  ('60000000-0000-0000-0000-000000000003', '40000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000003', 'Hey! Carol here. I work on the database systems research group.', '2024-01-13 10:15:00'),
  ('60000000-0000-0000-0000-000000000004', '40000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002', 'Quick note: the CS301 midterm will cover graph algorithms and perpendicular bisectors in computational geometry.', '2024-01-20 14:00:00'),
  ('60000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'Reminder: faculty meeting on Friday at 3pm in Room 204.', '2024-01-22 09:00:00'),
  ('60000000-0000-0000-0000-000000000006', '40000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001', 'Carol, can you review the rubric for the final project?', '2024-01-15 11:00:00'),
  ('60000000-0000-0000-0000-000000000007', '40000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000003', 'Sure! The perpendicular distance metric in question 3 needs a clearer definition.', '2024-01-15 11:45:00'),
  ('60000000-0000-0000-0000-000000000008', '40000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001', 'Good catch. I will update the rubric tonight.', '2024-01-15 12:00:00'),
  ('60000000-0000-0000-0000-000000000009', '40000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000001', 'Bob, three students asked for extensions. I already approved them.', '2024-01-18 08:30:00'),
  ('60000000-0000-0000-0000-000000000010', '40000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000002', 'Thanks for letting me know! I will keep an eye out for their late submissions.', '2024-01-18 09:00:00'),
  ('60000000-0000-0000-0000-000000000011', '40000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000004', 'Team, we are switching the API to REST. All endpoints need to be documented by end of sprint.', '2024-02-01 09:00:00'),
  ('60000000-0000-0000-0000-000000000012', '40000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000005', 'Should we use perpendicular versioning or date-based versioning for the API?', '2024-02-01 09:30:00'),
  ('60000000-0000-0000-0000-000000000013', '40000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000003', 'I would recommend semantic versioning. It is the industry standard.', '2024-02-05 13:00:00'),
  ('60000000-0000-0000-0000-000000000014', '40000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000004', 'Agreed. Eve please set up the OpenAPI spec doc in the repo.', '2024-02-05 13:30:00'),
  ('60000000-0000-0000-0000-000000000015', '40000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000004', 'Carol, the board wants a demo next Tuesday. Are we in good shape on the backend?', '2024-02-06 09:05:00'),
  ('60000000-0000-0000-0000-000000000016', '40000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000003', 'We should be fine. The database schema is solid.', '2024-02-06 09:30:00');
